  1â†’package main
  2â†’
  3â†’import (
  4â†’	"context"
  5â†’	"flag"
  6â†’	"fmt"
  7â†’	"log/slog"
  8â†’	"time"
  9â†’
 10â†’	"github.com/jackc/pgx/v5/pgxpool"
 11â†’	"github.com/ketang/kapow/tools/kapow/internal/config"
 12â†’	"github.com/ketang/kapow/tools/kapow/internal/fetch"
 13â†’)
 14â†’
 15â†’// Importer defines the interface that all data importers must implement.
 16â†’type Importer interface {
 17â†’	// Name returns the subcommand name (e.g. "nces", "rankings").
 18â†’	Name() string
 19â†’	// Description returns a short human-readable description.
 20â†’	Description() string
 21â†’	// Dependencies returns names of importers that must run before this one.
 22â†’	Dependencies() []string
 23â†’	// RegisterFlags adds importer-specific flags to the given FlagSet.
 24â†’	RegisterFlags(fs *flag.FlagSet)
 25â†’	// Run executes the import. It may use the pool for DB operations and the
 26â†’	// fetcher for downloading source data.
 27â†’	Run(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher) error
 28â†’}
 29â†’
 30â†’// registry holds all registered importers keyed by name.
 31â†’var registry = map[string]Importer{}
 32â†’
 33â†’// Register adds an importer to the registry. Panics on duplicate name.
 34â†’func Register(imp Importer) {
 35â†’	name := imp.Name()
 36â†’	if _, exists := registry[name]; exists {
 37â†’		panic(fmt.Sprintf("importer: duplicate registration: %s", name))
 38â†’	}
 39â†’	registry[name] = imp
 40â†’}
 41â†’
 42â†’// Get returns a registered importer by name, or nil if not found.
 43â†’func Get(name string) Importer {
 44â†’	return registry[name]
 45â†’}
 46â†’
 47â†’// All returns all registered importers.
 48â†’func All() map[string]Importer {
 49â†’	return registry
 50â†’}
 51â†’
 52â†’// RunAll executes all importers in dependency order.
 53â†’func RunAll(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher, skip, only map[string]bool) error {
 54â†’	ordered, err := topoSort(registry)
 55â†’	if err != nil {
 56â†’		return err
 57â†’	}
 58â†’
 59â†’	for _, imp := range ordered {
 60â†’		name := imp.Name()
 61â†’		if len(only) > 0 && !only[name] {
 62â†’			slog.Info("run-all: skipping (not in --only)", "importer", name)
 63â†’			continue
 64â†’		}
 65â†’		if skip[name] {
 66â†’			slog.Info("run-all: skipping (in --skip)", "importer", name)
 67â†’			continue
 68â†’		}
 69â†’
 70â†’		slog.Info("run-all: starting", "importer", name)
 71â†’		start := time.Now()
 72â†’		if err := imp.Run(ctx, cfg, pool, fetcher); err != nil {
 73â†’			return fmt.Errorf("run-all: %s: %w", name, err)
 74â†’		}
 75â†’		slog.Info("run-all: completed", "importer", name, "duration", time.Since(start).Round(time.Millisecond))
 76â†’	}
 77â†’
 78â†’	return nil
 79â†’}
 80â†’
 81â†’// topoSort returns importers in dependency order using Kahn's algorithm.
 82â†’func topoSort(importers map[string]Importer) ([]Importer, error) {
 83â†’	// Build in-degree map and adjacency list.
 84â†’	inDegree := make(map[string]int)
 85â†’	dependents := make(map[string][]string) // dep -> list of importers that depend on it
 86â†’
 87â†’	for name, imp := range importers {
 88â†’		if _, ok := inDegree[name]; !ok {
 89â†’			inDegree[name] = 0
 90â†’		}
 91â†’		for _, dep := range imp.Dependencies() {
 92â†’			inDegree[name]++
 93â†’			dependents[dep] = append(dependents[dep], name)
 94â†’		}
 95â†’	}
 96â†’
 97â†’	// Start with importers that have no dependencies.
 98â†’	var queue []string
 99â†’	for name, deg := range inDegree {
100â†’		if deg == 0 {
101â†’			queue = append(queue, name)
102â†’		}
103â†’	}
104â†’
105â†’	var result []Importer
106â†’	for len(queue) > 0 {
107â†’		name := queue[0]
108â†’		queue = queue[1:]
109â†’		if imp, ok := importers[name]; ok {
110â†’			result = append(result, imp)
111â†’		}
112â†’		for _, dep := range dependents[name] {
113â†’			inDegree[dep]--
114â†’			if inDegree[dep] == 0 {
115â†’				queue = append(queue, dep)
116â†’			}
117â†’		}
118â†’	}
119â†’
120â†’	if len(result) != len(importers) {
121â†’		return nil, fmt.Errorf("importer: circular dependency detected")
122â†’	}
123â†’
124â†’	return result, nil
125â†’}
126â†’

  1â†’package main
  2â†’
  3â†’import (
  4â†’	"context"
  5â†’	"encoding/json"
  6â†’	"errors"
  7â†’	"flag"
  8â†’	"fmt"
  9â†’	"log/slog"
 10â†’	"sort"
 11â†’	"strings"
 12â†’	"time"
 13â†’
 14â†’	"github.com/jackc/pgx/v5/pgxpool"
 15â†’	"github.com/ketang/kapow/tools/kapow/internal/config"
 16â†’	"github.com/ketang/kapow/tools/kapow/internal/dbutil"
 17â†’	"github.com/ketang/kapow/tools/kapow/internal/fetch"
 18â†’	"github.com/ketang/kapow/tools/kapow/internal/namematch"
 19â†’	"github.com/ketang/kapow/tools/kapow/internal/platform"
 20â†’	"github.com/ketang/kapow/tools/kapow/internal/scraper"
 21â†’)
 22â†’
 23â†’func init() {
 24â†’	Register(&admissionsImporter{})
 25â†’}
 26â†’
 27â†’type admissionsImporter struct {
 28â†’	maxCacheAge time.Duration
 29â†’	requireAll  bool
 30â†’	platforms   string
 31â†’}
 32â†’
 33â†’func (a *admissionsImporter) Name() string        { return "admissions" }
 34â†’func (a *admissionsImporter) Description() string  { return "Import application platform membership data" }
 35â†’func (a *admissionsImporter) Dependencies() []string { return nil }
 36â†’
 37â†’func (a *admissionsImporter) RegisterFlags(fs *flag.FlagSet) {
 38â†’	fs.DurationVar(&a.maxCacheAge, "max-cache-age", 7*24*time.Hour, "maximum cache age before re-scraping")
 39â†’	fs.BoolVar(&a.requireAll, "require-all", false, "fail if any scraper errors")
 40â†’	fs.StringVar(&a.platforms, "platforms", "", "comma-separated platform keys to run (default: all)")
 41â†’}
 42â†’
 43â†’func (a *admissionsImporter) Run(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher) error {
 44â†’	// Load name matcher from DB.
 45â†’	matcher, err := namematch.Load(ctx, pool)
 46â†’	if err != nil {
 47â†’		return fmt.Errorf("admissions: load matcher: %w", err)
 48â†’	}
 49â†’
 50â†’	// Initialize headless browser.
 51â†’	browser, err := scraper.New()
 52â†’	if err != nil {
 53â†’		return fmt.Errorf("admissions: create browser: %w", err)
 54â†’	}
 55â†’	defer browser.Close()
 56â†’
 57â†’	cache := scraper.NewCache(fetcher.CacheDir(), a.maxCacheAge)
 58â†’	filter := parsePlatformFilter(a.platforms)
 59â†’	extractors := platform.All()
 60â†’
 61â†’	// Scrape (or load from cache) each platform.
 62â†’	platformNames, errs := scrapeAll(ctx, extractors, browser, cache, filter)
 63â†’
 64â†’	if a.requireAll && len(errs) > 0 {
 65â†’		return fmt.Errorf("admissions: %d extractor(s) failed: %w", len(errs), errors.Join(errs...))
 66â†’	}
 67â†’
 68â†’	// Match names to unit IDs and aggregate platforms per institution.
 69â†’	admissions, stats := aggregateAdmissions(platformNames, matcher)
 70â†’
 71â†’	// Log per-platform stats.
 72â†’	for _, s := range stats {
 73â†’		slog.Info("admissions: platform stats",
 74â†’			"platform", s.key,
 75â†’			"scraped", s.scraped,
 76â†’			"matched", s.matched,
 77â†’			"unmatched", s.unmatched,
 78â†’		)
 79â†’	}
 80â†’
 81â†’	// Build JSONB payloads and write to DB.
 82â†’	bulkData, err := buildAdmissionsJSON(admissions)
 83â†’	if err != nil {
 84â†’		return fmt.Errorf("admissions: build json: %w", err)
 85â†’	}
 86â†’
 87â†’	if err := dbutil.BulkSetAdmissions(ctx, pool, bulkData); err != nil {
 88â†’		return fmt.Errorf("admissions: bulk upsert: %w", err)
 89â†’	}
 90â†’
 91â†’	slog.Info("admissions: complete", "institutions_updated", len(bulkData))
 92â†’	return nil
 93â†’}
 94â†’
 95â†’// parsePlatformFilter converts a comma-separated string of platform keys into
 96â†’// a set. An empty string means "all platforms".
 97â†’func parsePlatformFilter(s string) map[string]bool {
 98â†’	s = strings.TrimSpace(s)
 99â†’	if s == "" {
100â†’		return nil
101â†’	}
102â†’	m := make(map[string]bool)
103â†’	for _, k := range strings.Split(s, ",") {
104â†’		k = strings.TrimSpace(k)
105â†’		if k != "" {
106â†’			m[k] = true
107â†’		}
108â†’	}
109â†’	return m
110â†’}
111â†’
112â†’// scrapeAll runs each extractor (checking cache first) and returns a map of
113â†’// platform key â†’ institution names. Errors from individual extractors are
114â†’// collected and returned separately.
115â†’func scrapeAll(ctx context.Context, extractors []platform.Extractor, browser *scraper.Browser, cache *scraper.Cache, filter map[string]bool) (map[string][]string, []error) {
116â†’	result := make(map[string][]string)
117â†’	var errs []error
118â†’
119â†’	for _, ext := range extractors {
120â†’		key := ext.Key()
121â†’		if filter != nil && !filter[key] {
122â†’			slog.Debug("admissions: skipping platform (filtered)", "platform", key)
123â†’			continue
124â†’		}
125â†’
126â†’		names, err := loadOrScrape(ctx, ext, browser, cache)
127â†’		if err != nil {
128â†’			slog.Warn("admissions: extractor failed", "platform", key, "error", err)
129â†’			errs = append(errs, fmt.Errorf("%s: %w", key, err))
130â†’			continue
131â†’		}
132â†’
133â†’		result[key] = names
134â†’		slog.Info("admissions: scraped", "platform", key, "institutions", len(names))
135â†’	}
136â†’
137â†’	return result, errs
138â†’}
139â†’
140â†’// loadOrScrape attempts to load cached results; on miss or stale, runs the
141â†’// extractor and saves the result to cache.
142â†’func loadOrScrape(ctx context.Context, ext platform.Extractor, browser *scraper.Browser, cache *scraper.Cache) ([]string, error) {
143â†’	names, err := cache.Load(ext.Key())
144â†’	if err == nil {
145â†’		slog.Debug("admissions: cache hit", "platform", ext.Key(), "institutions", len(names))
146â†’		return names, nil
147â†’	}
148â†’
149â†’	names, err = ext.Extract(ctx, browser)
150â†’	if err != nil {
151â†’		return nil, err
152â†’	}
153â†’
154â†’	if saveErr := cache.Save(ext.Key(), names); saveErr != nil {
155â†’		slog.Warn("admissions: cache save failed", "platform", ext.Key(), "error", saveErr)
156â†’	}
157â†’
158â†’	return names, nil
159â†’}
160â†’
161â†’// platformStat tracks scrape/match statistics for a single platform.
162â†’type platformStat struct {
163â†’	key       string
164â†’	scraped   int
165â†’	matched   int
166â†’	unmatched int
167â†’}
168â†’
169â†’// aggregateAdmissions matches institution names from each platform to unit IDs
170â†’// and builds a map of unitID â†’ sorted platform keys.
171â†’func aggregateAdmissions(platformNames map[string][]string, matcher *namematch.Matcher) (map[string][]string, []platformStat) {
172â†’	byUnit := make(map[string]map[string]bool)
173â†’	var stats []platformStat
174â†’
175â†’	// Process platforms in sorted order for deterministic output.
176â†’	keys := make([]string, 0, len(platformNames))
177â†’	for k := range platformNames {
178â†’		keys = append(keys, k)
179â†’	}
180â†’	sort.Strings(keys)
181â†’
182â†’	for _, key := range keys {
183â†’		names := platformNames[key]
184â†’		s := platformStat{key: key, scraped: len(names)}
185â†’
186â†’		for _, name := range names {
187â†’			unitID, ok := matcher.Match(name)
188â†’			if !ok {
189â†’				s.unmatched++
190â†’				slog.Debug("admissions: unmatched", "platform", key, "name", name)
191â†’				continue
192â†’			}
193â†’			s.matched++
194â†’			if byUnit[unitID] == nil {
195â†’				byUnit[unitID] = make(map[string]bool)
196â†’			}
197â†’			byUnit[unitID][key] = true
198â†’		}
199â†’		stats = append(stats, s)
200â†’	}
201â†’
202â†’	// Convert sets to sorted slices.
203â†’	result := make(map[string][]string, len(byUnit))
204â†’	for unitID, keySet := range byUnit {
205â†’		sorted := make([]string, 0, len(keySet))
206â†’		for k := range keySet {
207â†’			sorted = append(sorted, k)
208â†’		}
209â†’		sort.Strings(sorted)
210â†’		result[unitID] = sorted
211â†’	}
212â†’
213â†’	return result, stats
214â†’}
215â†’
216â†’// admissionsPayload is the JSON structure stored in the admissions column.
217â†’type admissionsPayload struct {
218â†’	Applications []string `json:"applications"`
219â†’}
220â†’
221â†’// buildAdmissionsJSON converts the aggregated map into serialized JSON
222â†’// suitable for BulkSetAdmissions.
223â†’func buildAdmissionsJSON(admissions map[string][]string) (map[string][]byte, error) {
224â†’	result := make(map[string][]byte, len(admissions))
225â†’	for unitID, platforms := range admissions {
226â†’		payload := admissionsPayload{Applications: platforms}
227â†’		data, err := json.Marshal(payload)
228â†’		if err != nil {
229â†’			return nil, fmt.Errorf("marshal %s: %w", unitID, err)
230â†’		}
231â†’		result[unitID] = data
232â†’	}
233â†’	return result, nil
234â†’}
