  1â†’package deadlines
  2â†’
  3â†’import (
  4â†’	"bytes"
  5â†’	"context"
  6â†’	"encoding/json"
  7â†’	"fmt"
  8â†’	"io"
  9â†’	"net/http"
 10â†’	"regexp"
 11â†’	"strings"
 12â†’	"time"
 13â†’	"unicode"
 14â†’)
 15â†’
 16â†’const (
 17â†’	bigfutureBaseURL = "https://bigfuture.collegeboard.org/colleges/"
 18â†’	bigfuturePageType = "bigfuture"
 19â†’)
 20â†’
 21â†’// BigFutureData holds the admissions-related fields from BigFuture's
 22â†’// __NEXT_DATA__ JSON (props.pageProps.collegeData).
 23â†’type BigFutureData struct {
 24â†’	OrgID                        string   `json:"orgId"`
 25â†’	DICode                       string   `json:"diCode"`
 26â†’	IPEDSId                      string   `json:"ipedsId"`
 27â†’	EarlyDecision                bool     `json:"earlyDecision"`
 28â†’	EarlyDecisionDate            string   `json:"earlyDecisionDate"`
 29â†’	EarlyActionDate              string   `json:"earlyActionDate"`
 30â†’	RegularDecisionDate          string   `json:"regularDecisionDate"`
 31â†’	NotificationDate             string   `json:"notificationDate"`
 32â†’	ResponseDeadline             string   `json:"responseDeadline"`
 33â†’	FinancialAidRegularDeadline  string   `json:"financialAidApplicationRegularDeadline"`
 34â†’	FinancialAidPriorityDeadline string   `json:"financialAidApplicationPriorityDeadline"`
 35â†’	ApplicationSiteURL           string   `json:"applicationSiteUrl"`
 36â†’	ApplicationsAccepted         []string `json:"applicationsAccepted"`
 37â†’}
 38â†’
 39â†’// nextDataEnvelope mirrors the __NEXT_DATA__ JSON structure down to collegeData.
 40â†’type nextDataEnvelope struct {
 41â†’	Props struct {
 42â†’		PageProps struct {
 43â†’			CollegeData BigFutureData `json:"collegeData"`
 44â†’		} `json:"pageProps"`
 45â†’	} `json:"props"`
 46â†’}
 47â†’
 48â†’// BigFutureURL returns the full BigFuture URL for a given slug.
 49â†’func BigFutureURL(slug string) string {
 50â†’	return bigfutureBaseURL + slug
 51â†’}
 52â†’
 53â†’// FetchPage performs an HTTP GET to fetch a BigFuture college page and returns
 54â†’// the raw HTML bytes.
 55â†’func FetchPage(ctx context.Context, client *http.Client, slug string) ([]byte, int, error) {
 56â†’	url := BigFutureURL(slug)
 57â†’
 58â†’	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
 59â†’	if err != nil {
 60â†’		return nil, 0, fmt.Errorf("deadlines: bigfuture: create request %s: %w", slug, err)
 61â†’	}
 62â†’	req.Header.Set("User-Agent", "Kapow/1.0 (+https://github.com/ketang/kapow)")
 63â†’	req.Header.Set("Accept", "text/html")
 64â†’
 65â†’	resp, err := client.Do(req)
 66â†’	if err != nil {
 67â†’		return nil, 0, fmt.Errorf("deadlines: bigfuture: fetch %s: %w", slug, err)
 68â†’	}
 69â†’	defer resp.Body.Close()
 70â†’
 71â†’	body, err := io.ReadAll(resp.Body)
 72â†’	if err != nil {
 73â†’		return nil, resp.StatusCode, fmt.Errorf("deadlines: bigfuture: read body %s: %w", slug, err)
 74â†’	}
 75â†’
 76â†’	if resp.StatusCode != http.StatusOK {
 77â†’		return nil, resp.StatusCode, fmt.Errorf("deadlines: bigfuture: %s returned status %d", slug, resp.StatusCode)
 78â†’	}
 79â†’
 80â†’	return body, resp.StatusCode, nil
 81â†’}
 82â†’
 83â†’var (
 84â†’	nextDataStart = []byte(`<script id="__NEXT_DATA__" type="application/json">`)
 85â†’	nextDataEnd   = []byte(`</script>`)
 86â†’)
 87â†’
 88â†’// ParseNextData extracts the __NEXT_DATA__ JSON from BigFuture HTML and
 89â†’// returns the parsed college data.
 90â†’func ParseNextData(html []byte) (*BigFutureData, error) {
 91â†’	startIdx := bytes.Index(html, nextDataStart)
 92â†’	if startIdx < 0 {
 93â†’		return nil, fmt.Errorf("deadlines: bigfuture: __NEXT_DATA__ script tag not found")
 94â†’	}
 95â†’	jsonStart := startIdx + len(nextDataStart)
 96â†’
 97â†’	endIdx := bytes.Index(html[jsonStart:], nextDataEnd)
 98â†’	if endIdx < 0 {
 99â†’		return nil, fmt.Errorf("deadlines: bigfuture: __NEXT_DATA__ closing script tag not found")
100â†’	}
101â†’
102â†’	jsonBytes := html[jsonStart : jsonStart+endIdx]
103â†’
104â†’	var envelope nextDataEnvelope
105â†’	if err := json.Unmarshal(jsonBytes, &envelope); err != nil {
106â†’		return nil, fmt.Errorf("deadlines: bigfuture: parse __NEXT_DATA__ JSON: %w", err)
107â†’	}
108â†’
109â†’	data := envelope.Props.PageProps.CollegeData
110â†’	return &data, nil
111â†’}
112â†’
113â†’// ToDeadlineData converts BigFuture data into the canonical DeadlineData format.
114â†’// The year parameter is the admission cycle year (e.g., 2026 for Fall 2026 entry).
115â†’func ToDeadlineData(bf *BigFutureData, year int) DeadlineData {
116â†’	sourceURL := BigFutureURL(slugFromOrgID(bf.OrgID, bf.DICode))
117â†’	now := time.Now().UTC().Format(time.RFC3339)
118â†’
119â†’	dd := DeadlineData{
120â†’		Plans:            make(map[string]DeadlinePlan),
121â†’		HasEarlyDecision: bf.EarlyDecision,
122â†’		HasEarlyAction:   bf.EarlyActionDate != "" && bf.EarlyActionDate != "null",
123â†’		SourceURLs:       []string{sourceURL},
124â†’		ExtractedAt:      now,
125â†’		BigfutureID:      bf.OrgID,
126â†’	}
127â†’
128â†’	// Early Decision
129â†’	if bf.EarlyDecision && bf.EarlyDecisionDate != "" {
130â†’		if d := convertDate(bf.EarlyDecisionDate, year); d != "" {
131â†’			dd.Plans[PlanEarlyDecision1] = DeadlinePlan{
132â†’				Deadline:   d,
133â†’				Binding:    true,
134â†’				SourceURL:  sourceURL,
135â†’				Confidence: "medium",
136â†’			}
137â†’		}
138â†’	}
139â†’
140â†’	// Early Action
141â†’	if bf.EarlyActionDate != "" {
142â†’		if d := convertDate(bf.EarlyActionDate, year); d != "" {
143â†’			dd.Plans[PlanEarlyAction] = DeadlinePlan{
144â†’				Deadline:   d,
145â†’				SourceURL:  sourceURL,
146â†’				Confidence: "medium",
147â†’			}
148â†’		}
149â†’	}
150â†’
151â†’	// Regular Decision
152â†’	if bf.RegularDecisionDate != "" {
153â†’		plan := DeadlinePlan{
154â†’			SourceURL:  sourceURL,
155â†’			Confidence: "medium",
156â†’		}
157â†’		if d := convertDate(bf.RegularDecisionDate, year+1); d != "" {
158â†’			plan.Deadline = d
159â†’		}
160â†’		// Notification date goes on the regular plan.
161â†’		if d := convertDate(bf.NotificationDate, year+1); d != "" {
162â†’			plan.Notification = d
163â†’		}
164â†’		if plan.Deadline != "" || plan.Notification != "" {
165â†’			dd.Plans[PlanRegular] = plan
166â†’		}
167â†’	}
168â†’
169â†’	return dd
170â†’}
171â†’
172â†’// convertDate converts a BigFuture date string (MM/DD/9999) to YYYY-MM-DD
173â†’// using the given year. Returns empty string for null, empty, or unparseable dates.
174â†’func convertDate(s string, year int) string {
175â†’	s = strings.TrimSpace(s)
176â†’	if s == "" || s == "null" {
177â†’		return ""
178â†’	}
179â†’
180â†’	// Expected format: MM/DD/YYYY (where YYYY is often 9999).
181â†’	parts := strings.Split(s, "/")
182â†’	if len(parts) != 3 {
183â†’		return ""
184â†’	}
185â†’
186â†’	month := parts[0]
187â†’	day := parts[1]
188â†’
189â†’	// Validate month and day are numeric and in range.
190â†’	if len(month) < 1 || len(month) > 2 || len(day) < 1 || len(day) > 2 {
191â†’		return ""
192â†’	}
193â†’
194â†’	return fmt.Sprintf("%04d-%s-%s", year, zeroPad(month), zeroPad(day))
195â†’}
196â†’
197â†’// zeroPad ensures a 1-2 digit string is zero-padded to 2 digits.
198â†’func zeroPad(s string) string {
199â†’	if len(s) == 1 {
200â†’		return "0" + s
201â†’	}
202â†’	return s
203â†’}
204â†’
205â†’// slugFromOrgID is a fallback slug builder when we only have IDs, not a name.
206â†’func slugFromOrgID(orgID, diCode string) string {
207â†’	if orgID != "" {
208â†’		return orgID
209â†’	}
210â†’	return diCode
211â†’}
212â†’
213â†’var slugReplacer = regexp.MustCompile(`[^a-z0-9]+`)
214â†’
215â†’// SlugFromName converts an institution name to a BigFuture-style kebab-case slug.
216â†’func SlugFromName(name string) string {
217â†’	// Lowercase.
218â†’	s := strings.ToLower(name)
219â†’
220â†’	// Remove apostrophes and periods (BigFuture strips these rather than
221â†’	// replacing with hyphens).
222â†’	s = strings.NewReplacer("'", "", "'", "", ".", "").Replace(s)
223â†’
224â†’	// Replace any run of non-alphanumeric characters with a single hyphen.
225â†’	s = slugReplacer.ReplaceAllString(s, "-")
226â†’
227â†’	// Trim leading/trailing hyphens.
228â†’	s = strings.Trim(s, "-")
229â†’
230â†’	// Strip any remaining non-ASCII (safety net).
231â†’	s = strings.Map(func(r rune) rune {
232â†’		if r > unicode.MaxASCII {
233â†’			return -1
234â†’		}
235â†’		return r
236â†’	}, s)
237â†’
238â†’	return s
239â†’}
