  1â†’// Package namematch provides deterministic institution name matching.
  2â†’//
  3â†’// It loads all institutions and aliases from the database into in-memory maps
  4â†’// and resolves input names to unit_id values via a 3-tier lookup:
  5â†’//
  6â†’//  1. Exact lowercase match against institution_name
  7â†’//  2. Normalized match (diacritics stripped, punctuation removed, etc.)
  8â†’//  3. Builtin alias overrides for common external-source name variants
  9â†’//  4. DB alias match from search_base.institution_alias
 10â†’//
 11â†’// MatchByOPE6 and MatchByOPE8 provide direct lookups by OPE ID.
 12â†’package namematch
 13â†’
 14â†’import (
 15â†’	"context"
 16â†’	"fmt"
 17â†’	"strings"
 18â†’
 19â†’	"github.com/jackc/pgx/v5/pgxpool"
 20â†’)
 21â†’
 22â†’// Matcher holds in-memory lookup maps for deterministic name resolution.
 23â†’type Matcher struct {
 24â†’	exact      map[string]string // strings.ToLower(institution_name) â†’ unit_id
 25â†’	normalized map[string]string // Normalize(institution_name) â†’ unit_id
 26â†’	alias      map[string]string // strings.ToLower(db alias) â†’ unit_id
 27â†’	ope6       map[string]string // ope6_id â†’ unit_id
 28â†’	ope8       map[string]string // ope8_id â†’ unit_id
 29â†’}
 30â†’
 31â†’// Load queries all institutions and aliases from the database and returns a
 32â†’// ready-to-use Matcher. The pool must be connected and the schema must be
 33â†’// populated.
 34â†’func Load(ctx context.Context, pool *pgxpool.Pool) (*Matcher, error) {
 35â†’	m := &Matcher{
 36â†’		exact:      make(map[string]string),
 37â†’		normalized: make(map[string]string),
 38â†’		alias:      make(map[string]string),
 39â†’		ope6:       make(map[string]string),
 40â†’		ope8:       make(map[string]string),
 41â†’	}
 42â†’
 43â†’	if err := m.loadInstitutions(ctx, pool); err != nil {
 44â†’		return nil, fmt.Errorf("namematch: load institutions: %w", err)
 45â†’	}
 46â†’	if err := m.loadAliases(ctx, pool); err != nil {
 47â†’		return nil, fmt.Errorf("namematch: load aliases: %w", err)
 48â†’	}
 49â†’	return m, nil
 50â†’}
 51â†’
 52â†’func (m *Matcher) loadInstitutions(ctx context.Context, pool *pgxpool.Pool) error {
 53â†’	rows, err := pool.Query(ctx,
 54â†’		`SELECT unit_id, institution_name, ope6_id, ope8_id FROM search_base.institution`)
 55â†’	if err != nil {
 56â†’		return err
 57â†’	}
 58â†’	defer rows.Close()
 59â†’
 60â†’	for rows.Next() {
 61â†’		var unitID, name, ope6, ope8 string
 62â†’		if err := rows.Scan(&unitID, &name, &ope6, &ope8); err != nil {
 63â†’			return err
 64â†’		}
 65â†’		m.exact[strings.ToLower(name)] = unitID
 66â†’		m.normalized[Normalize(name)] = unitID
 67â†’		if ope6 != "" {
 68â†’			m.ope6[ope6] = unitID
 69â†’		}
 70â†’		if ope8 != "" {
 71â†’			m.ope8[ope8] = unitID
 72â†’		}
 73â†’	}
 74â†’	return rows.Err()
 75â†’}
 76â†’
 77â†’func (m *Matcher) loadAliases(ctx context.Context, pool *pgxpool.Pool) error {
 78â†’	rows, err := pool.Query(ctx,
 79â†’		`SELECT unit_id, alias FROM search_base.institution_alias`)
 80â†’	if err != nil {
 81â†’		return err
 82â†’	}
 83â†’	defer rows.Close()
 84â†’
 85â†’	for rows.Next() {
 86â†’		var unitID, alias string
 87â†’		if err := rows.Scan(&unitID, &alias); err != nil {
 88â†’			return err
 89â†’		}
 90â†’		m.alias[strings.ToLower(alias)] = unitID
 91â†’	}
 92â†’	return rows.Err()
 93â†’}
 94â†’
 95â†’// Match resolves an institution name to its unit_id using a 3-tier lookup:
 96â†’//  1. Exact lowercase match
 97â†’//  2. Normalized match
 98â†’//  3. Builtin alias (normalized input â†’ canonical name â†’ normalized lookup)
 99â†’//  4. DB alias (lowercase)
100â†’//
101â†’// Returns ("", false) if no match is found.
102â†’func (m *Matcher) Match(name string) (unitID string, ok bool) {
103â†’	// Tier 1: exact lowercase
104â†’	lower := strings.ToLower(name)
105â†’	if uid, found := m.exact[lower]; found {
106â†’		return uid, true
107â†’	}
108â†’
109â†’	// Tier 2: normalized
110â†’	nkey := Normalize(name)
111â†’	if uid, found := m.normalized[nkey]; found {
112â†’		return uid, true
113â†’	}
114â†’
115â†’	// Tier 3: builtin alias â†’ normalize canonical name â†’ normalized lookup
116â†’	if canonical, found := builtinAliases[nkey]; found {
117â†’		if uid, found := m.normalized[Normalize(canonical)]; found {
118â†’			return uid, true
119â†’		}
120â†’	}
121â†’
122â†’	// Tier 4: DB alias (lowercase)
123â†’	if uid, found := m.alias[lower]; found {
124â†’		return uid, true
125â†’	}
126â†’
127â†’	return "", false
128â†’}
129â†’
130â†’// MatchByOPE6 looks up an institution by its 6-digit OPE ID.
131â†’func (m *Matcher) MatchByOPE6(ope6 string) (unitID string, ok bool) {
132â†’	uid, found := m.ope6[ope6]
133â†’	return uid, found
134â†’}
135â†’
136â†’// MatchByOPE8 looks up an institution by its 8-digit OPE ID.
137â†’func (m *Matcher) MatchByOPE8(ope8 string) (unitID string, ok bool) {
138â†’	uid, found := m.ope8[ope8]
139â†’	return uid, found
140â†’}
141â†’

