			return uid
		}
	}

	return ""
}

// buildSlugList creates the list of slugs to process, either from a file or
// from DB institution names.
func (b *bigfutureImporter) buildSlugList(ctx context.Context, pool *pgxpool.Pool) ([]slugEntry, error) {
	if b.slugFile != "" {
		return loadSlugFile(b.slugFile)
	}
	return buildSlugsFromDB(ctx, pool)
}

// loadSlugFile reads a file with one slug per line.
func loadSlugFile(path string) ([]slugEntry, error) {
	f, err := os.Open(path)
	if err != nil {
		return nil, fmt.Errorf("open slug file: %w", err)
	}
	defer f.Close()

	var entries []slugEntry
	scanner := bufio.NewScanner(f)
	for scanner.Scan() {
		slug := strings.TrimSpace(scanner.Text())
		if slug == "" || strings.HasPrefix(slug, "#") {
			continue
		}
		entries = append(entries, slugEntry{slug: slug})
	}
	if err := scanner.Err(); err != nil {
		return nil, fmt.Errorf("read slug file: %w", err)
	}
	return entries, nil
